// Map de Realworks broker.brokerobject/save payload naar WordPress ACF-velden.
// De extensie stuurt ruwe codes + gedecodeerde labels (<veld>_label) en _display-velden.
const body = $input.first().json.body;

if (!body || (!body.objectcode && !body.lisnr)) {
  throw new Error('Geen objectcode/lisnr in payload — verplicht veld');
}

const realworksId = body.objectcode || body.lisnr;

// Nederlands getal "400.000,00" -> 400000
function num(v) {
  if (v === undefined || v === null || v === '') return undefined;
  const n = parseFloat(String(v).replace(/\./g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : undefined;
}

// Bouw het koopprijs-label op, bv. "Vraagprijs €400.000,-"
function priceLabel(typeLabel, amount) {
  const t = (typeLabel || '').trim();
  if (/aanvraag/i.test(t)) return t; // Prijs op aanvraag: geen bedrag tonen
  if (amount === undefined || amount === null || amount === 0) return t || undefined;
  const bedrag = new Intl.NumberFormat('nl-NL').format(amount);
  return (t ? t + ' ' : '') + '€' + bedrag + ',-';
}

const huisnummer = [body.liststrnr, body.house_letter, body.house_number_extension]
  .filter(Boolean).join('').trim() || undefined;

// Bouw de ACF-set op; lege waarden laten we weg zodat bestaande WP-data niet gewist wordt.
const raw = {
  status: body.lisstate_label,
  koopsom: num(body.lissalepr),
  koopprijs_label: priceLabel(body.lissalepre_label, num(body.lissalepr)),
  huurprijs: num(body.lisrentpr),
  koopconditie: body.lissalecon_label,
  aanvaarding: body.lisaccocode_label,
  woonoppervlakte: num(body.reslivspac),
  kadastrale_oppervlakte: num(body.ressurface),
  inhoud: num(body.resvolume),
  aantal_kamers: num(body.resrooms),
  bouwjaar: body.resyearcon,
  bouwvorm: body.lisnewexi_label,
  woonhuissoort: body.soortwoning_label,
  woonhuistype: body.typewoning_label,
  energieklasse: body.energieklasse_label,
  energielabel_datum: body.energieeinddatum,
  postcode: body.liszipcode,
  plaats: body.liscity,
  provincie: body.lisprov,
  straat: body.lisstreet,
  huisnummer,
  aanbiedingstekst: body.listxtalg,
  isolatievormen: body.isolatievorm_display,
  verwarming: body.soortenverwarmingv14_display,
  voorzieningen: body.voorzieningwonen_display,
  ligging: body.liggingen_display,
};

const acf = {};
for (const [k, v] of Object.entries(raw)) {
  if (v !== undefined && v !== null && v !== '') acf[k] = v;
}

return [{ json: { realworksId, acf } }];

// De lookup geeft {found:false} terug als de woning niet (gepubliceerd) op de
// website staat, of {id, link, ...} als hij gevonden is.
const lookup = $input.first().json;
const mapped = $('Map naar ACF').first().json;

const found = lookup && lookup.id !== undefined && lookup.found !== false;

return [{
  json: {
    found,
    wpPostId: found ? lookup.id : null,
    wpLink: found ? lookup.link : null,
    realworksId: mapped.realworksId,
    acf: mapped.acf,
  }
}];
